// Sauvegarder le fichier ET son contenu dans le cache statique
const staticData = $getWorkflowStaticData('global');
const chatId = $json.chatId;
const fileName = $json.fileName || '';
const fileMime = $json.fileMimeType || '';
const docContent = $json.documentContent || '';
const extractMethod = $json.extractionMethod || 'none';

if (chatId && fileName) {
  staticData[`lastFile_${chatId}`] = {
    fileName,
    fileMimeType: fileMime,
    documentContent: docContent.substring(0, 5000),
    extractionMethod: extractMethod,
    timestamp: Date.now()
  };
}

const items = $input.all();
return items.map(item => ({
  json: item.json,
  binary: item.binary
}));

// Vérifier si un fichier a été envoyé récemment et enrichir avec son contenu
const staticData = $getWorkflowStaticData('global');
const items = $input.all();

return items.map(item => {
  const chatId = item.json.chatId;
  const lastFile = staticData[`lastFile_${chatId}`];
  const newJson = { ...item.json };

  if (lastFile && (Date.now() - lastFile.timestamp) < 300000) {
    let fileContext = '\n[Fichier récemment envoyé: ' + lastFile.fileName + ' (' + lastFile.fileMimeType + ')]';

    // Ajouter le contenu extrait si disponible
    if (lastFile.documentContent && lastFile.extractionMethod !== 'none' && !lastFile.documentContent.startsWith('[')) {
      fileContext += '\n\n--- CONTENU DU DOCUMENT ---\n' + lastFile.documentContent + '\n--- FIN DU CONTENU ---';
    } else if (lastFile.documentContent) {
      fileContext += '\n' + lastFile.documentContent;
    }

    newJson.messageText = (newJson.messageText || '') + fileContext;
    newJson.hasRecentFile = true;
    newJson.recentFileName = lastFile.fileName;
    newJson.recentFileMime = lastFile.fileMimeType;
  }

  return { json: newJson, binary: item.binary };
});

// Extraire le contenu textuel du document envoyé via Telegram
const items = $input.all();
const results = [];

for (const item of items) {
  const binaryObj = item.binary?.data;
  let documentContent = '';
  let extractionMethod = 'none';

  if (binaryObj) {
    const mimeType = binaryObj.mimeType || '';
    const fileName = binaryObj.fileName || '';

    try {
      const base64Data = binaryObj.data;

      if (base64Data && typeof base64Data === 'string') {
        const buffer = Buffer.from(base64Data, 'base64');

        // Fichiers texte : extraction directe UTF-8
        if (mimeType.startsWith('text/') ||
            ['application/json', 'application/xml', 'application/csv',
             'application/javascript', 'application/x-yaml'].includes(mimeType) ||
            fileName.match(/\.(txt|csv|json|xml|yaml|yml|md|html|htm|log|ini|cfg|conf|sh|js|ts|py|sql)$/i)) {
          documentContent = buffer.toString('utf-8').substring(0, 15000);
          extractionMethod = 'text_direct';
        }
        // PDF : extraction des chaînes de texte encodées
        else if (mimeType === 'application/pdf' || fileName.match(/\.pdf$/i)) {
          const raw = buffer.toString('latin1');
          const textParts = [];
          // Extraire texte entre parenthèses (opérateurs PDF Tj/TJ)
          const regex = /\(([^\\)]{0,500}(?:\\.[^\\)]{0,500})*)\)/g;
          let match;
          while ((match = regex.exec(raw)) !== null) {
            let text = match[1]
              .replace(/\\n/g, '\n')
              .replace(/\\r/g, '')
              .replace(/\\\(/g, '(')
              .replace(/\\\)/g, ')')
              .replace(/\\(.)/g, '$1');
            if (text.length > 0 && /[a-zA-Z\u00C0-\u00FF0-9]/.test(text)) {
              textParts.push(text);
            }
          }
          if (textParts.length > 0) {
            documentContent = textParts.join(' ').replace(/\s+/g, ' ').trim().substring(0, 15000);
            extractionMethod = 'pdf_text_extract';
          }
          if (!documentContent || documentContent.length < 50) {
            // Fallback : extraire séquences ASCII lisibles
            const printable = buffer.toString('utf-8')
              .replace(/[^\x20-\x7E\u00C0-\u00FF\n]/g, ' ')
              .replace(/\s{3,}/g, '\n')
              .trim()
              .substring(0, 15000);
            if (printable.length > 100) {
              documentContent = printable;
              extractionMethod = 'pdf_fallback';
            } else {
              documentContent = '[Document PDF: ' + fileName + ' - PDF scanné/image, contenu non extractible sans OCR]';
              extractionMethod = 'pdf_no_text';
            }
          }
        }
        // DOCX : extraction du texte depuis le XML interne
        else if (mimeType === 'application/vnd.openxmlformats-officedocument.wordprocessingml.document' || fileName.match(/\.docx$/i)) {
          const raw = buffer.toString('utf-8', 0, Math.min(buffer.length, 500000));
          const textParts = [];
          const regex = /<w:t[^>]*>([^<]+)<\/w:t>/g;
          let match;
          while ((match = regex.exec(raw)) !== null) {
            textParts.push(match[1]);
          }
          if (textParts.length > 0) {
            documentContent = textParts.join(' ').substring(0, 15000);
            extractionMethod = 'docx_xml_extract';
          } else {
            documentContent = '[Document DOCX: ' + fileName + ' - Contenu non extractible]';
            extractionMethod = 'docx_no_text';
          }
        }
        // XLS/XLSX : indication
        else if (fileName.match(/\.xlsx?$/i)) {
          documentContent = '[Fichier Excel: ' + fileName + ' - Format tableur, extraction limitée]';
          extractionMethod = 'excel_unsupported';
        }
        // Images : pas d OCR disponible
        else if (mimeType.startsWith('image/')) {
          documentContent = '[Image: ' + fileName + ' (' + mimeType + ') - Pas d\'extraction sans OCR]';
          extractionMethod = 'image_no_ocr';
        }
        else {
          documentContent = '[Document: ' + fileName + ' (' + mimeType + ') - Format non supporté]';
          extractionMethod = 'unsupported';
        }
      } else {
        // Données binaires stockées en référence (n8n récent)
        // Tenter via toString si possible
        documentContent = '[Document: ' + fileName + ' - Données en référence fichier]';
        extractionMethod = 'file_reference';
      }
    } catch (err) {
      documentContent = '[Erreur extraction: ' + err.message + ']';
      extractionMethod = 'error';
    }
  }

  results.push({
    json: { ...item.json, documentContent, extractionMethod },
    binary: item.binary
  });
}

return results;

